INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo tramito mi historial académico (kardex)?','Para tramitar tu historial académico (kardex), deberás realizar el pago correspondiente en caja y posteriormente presentar tu comprobante de pago en el Departamento de Control Escolar para dar inicio al trámite. La solicitud de concepto de pago puede solicitarse al correo caja@uttt.edu.mx. Para más información, puedes comunicarte al correo servicios.estudiantiles@uttt.edu.mx o al teléfono 773 732 9100 ext. 456.','alumnos',true,'["kardex uttt","historial academico","como sacar kardex","tramitar kardex","historial academico como obtener","kardex estudiantes uttt","solicitar historial academico","kardex control escolar","como pedir kardex","historial calificaciones completo","kardex universidad","tramite kardex estudiantes","historial academico requisitos","kardex donde sacar","kardex proceso uttt","como obtener historial academico","kardex calificaciones","historial escolar uttt","solicitud kardex","historial academico completo"]'::jsonb,'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');

