INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo solicito mi boleta de calificaciones?','Para solicitar tu boleta de calificaciones, deberás realizar el pago correspondiente en caja y posteriormente presentar o enviar vía correo electrónico tu comprobante de pago al Departamento de Control Escolar para dar inicio al trámite. La solicitud de concepto de pago puede solicitarse al correo caja@uttt.edu.mx. Para más información, puedes comunicarte al correo servicios.estudiantiles@uttt.edu.mx o al teléfono 773 732 9100 ext. 456.','alumnos',true,'["boleta de calificaciones","como sacar boleta","tramitar boleta uttt","boleta universidad como obtener","calificaciones boleta uttt","solicitar boleta calificaciones","boleta control escolar","como pedir boleta","boleta estudiantes uttt","boleta escolar universidad","tramite boleta estudiantes","boleta requisitos uttt","boleta donde sacar","boleta proceso uttt","como obtener boleta universidad","boleta calificaciones completo","boleta sige no aparece","boleta escolar uttt","solicitud boleta calificaciones","boleta notas universidad"]'::jsonb,'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');

