INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo puedo solicitar un duplicado de certificado?','Para solicitar un duplicado de certificado, deberás realizar el pago correspondiente en caja y posteriormente presentar tu comprobante de pago en el Departamento de Control Escolar para iniciar el trámite. El personal del área te indicará el tiempo estimado de entrega. La solicitud de concepto de pago puede solicitarse al correo caja@uttt.edu.mx. Para más información, puedes comunicarte al correo servicios.estudiantiles@uttt.edu.mx o al teléfono 773 732 9100 ext. 456.','alumnos',true,'["duplicado certificado estudios","reponer certificado universidad","certificado perdido que hago","tramitar duplicado certificado","duplicado certificado uttt","como sacar copia certificado","certificado extraviado universidad","solicitar duplicado certificado","certificado reposicion","como recuperar certificado estudios","duplicado certificado requisitos","certificado control escolar duplicado","tramite duplicado certificado","certificado copia universidad","certificado perdido reposicion","duplicado certificado escolar","solicitud duplicado certificado","certificado extraviado que hacer","duplicado certificado proceso","certificado universidad copia"]'::jsonb,'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');  

