INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Cuándo son las fechas de inscripción o reinscripción?','Las fechas de inscripción o reinscripción se dan a conocer a través de los medios oficiales de la universidad, por lo que se recomienda estar al pendiente de su publicación. Para más información, puedes comunicarte al correo servicios.estudiantiles@uttt.edu.mx o al teléfono 773 732 9100 ext. 456.','aspirantes',true,
'["fechas inscripcion uttt","cuando inscripciones universidad","fechas reinscripcion uttt","cuando me puedo inscribir","inscripciones universidad fechas","convocatoria inscripcion uttt","cuando hay reinscripciones","fechas de ingreso universidad","cuando salen fechas uttt","inscripcion universidad cuando es"]'::jsonb,
'Verónica Cruz Rico','Jefa de departamento','Departamento de Servicios Estudiantiles');

