INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES 
('¿Qué requisitos necesito para titularme?','Debes cumplir con requisitos como no tener adeudos, entregar documentación requerida, realizar pagos de titulación, concluir tu estadía y cumplir con los procesos establecidos en tiempo según la convocatoria vigente.','alumnos',true,
